#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

/*
 * Allocates a 2D matrix of doubles with the given dimensions.
 * Returns a pointer to an array of row pointers, where the underlying
 * data is stored in a single contiguous block for cache efficiency.
 *
 * Parameters:
 *   rows - number of rows in the matrix
 *   cols - number of columns in the matrix
 *
 * Returns:
 *   Pointer to array of row pointers (double**), or NULL on failure.
 *   The caller is responsible for freeing the matrix using free_matrix().
 */
double **allocate_matrix(size_t rows, size_t cols) {
    if (rows == 0 || cols == 0) {
        fprintf(stderr, "Error: rows and cols must be greater than 0.\n");
        return NULL;
    }

    /* Check for overflow in rows * cols */
    if (cols > 0 && rows > SIZE_MAX / cols) {
        fprintf(stderr, "Error: dimension overflow (rows * cols).\n");
        return NULL;
    }

    size_t total_elements = rows * cols;

    /* Check for overflow in total_elements * sizeof(double) */
    if (total_elements > SIZE_MAX / sizeof(double)) {
        fprintf(stderr, "Error: allocation size overflow.\n");
        return NULL;
    }

    size_t total_size = total_elements * sizeof(double);

    /* Allocate the contiguous data block */
    double *data = (double *)malloc(total_size);
    if (data == NULL) {
        fprintf(stderr, "Error: failed to allocate %zu bytes for matrix data.\n", total_size);
        return NULL;
    }

    /* Allocate the array of row pointers */
    double **matrix = (double **)malloc(rows * sizeof(double *));
    if (matrix == NULL) {
        fprintf(stderr, "Error: failed to allocate row pointer array.\n");
        free(data);
        return NULL;
    }

    /* Set up row pointers into the contiguous block */
    for (size_t i = 0; i < rows; i++) {
        matrix[i] = data + (i * cols);
    }

    /* Initialize all elements to zero */
    for (size_t i = 0; i < total_elements; i++) {
        data[i] = 0.0;
    }

    printf("Allocated %zu x %zu matrix (%zu bytes).\n", rows, cols, total_size);

    return matrix;
}

/*
 * Frees a matrix allocated by allocate_matrix().
 * Frees both the contiguous data block and the row pointer array.
 */
void free_matrix(double **matrix) {
    if (matrix != NULL) {
        /* matrix[0] points to the beginning of the contiguous data block */
        free(matrix[0]);
        free(matrix);
    }
}

/*
 * Prints the matrix contents (useful for debugging small matrices).
 */
void print_matrix(double **matrix, size_t rows, size_t cols) {
    if (matrix == NULL) {
        printf("(null matrix)\n");
        return;
    }
    for (size_t i = 0; i < rows; i++) {
        for (size_t j = 0; j < cols; j++) {
            printf("%10.4f ", matrix[i][j]);
        }
        printf("\n");
    }
}

